model_name = arguments.get('model')
if not model_name or model_name not in env:
    result = {'error': 'Model %r not found' % model_name}
else:
    record_id = arguments.get('id')
    if not record_id:
        result = {'error': 'Record ID is required'}
    else:
        body = arguments.get('body', '')
        if not body:
            result = {'error': 'Message body is required'}
        else:
            msg_type = arguments.get('type', 'comment')
            subtype = arguments.get('subtype')
            if msg_type == 'note':
                msg_type = 'comment'
                if not subtype:
                    subtype = 'mail.mt_note'
            if not subtype:
                subtype = 'mail.mt_comment'
            record = env[model_name].browse(record_id)
            msg = record.message_post(
                body=body,
                message_type=msg_type,
                subtype_xmlid=subtype,
            )
            result = {'id': msg.id, 'date': str(msg.date)}

{
    "type": "object",
    "properties": {
        "model": {
            "type": "string",
            "description": "Technical model name."
        },
        "id": {
            "type": "integer",
            "description": "The record ID to post the message on."
        },
        "body": {
            "type": "string",
            "description": "The message content (can contain HTML)."
        },
        "type": {
            "type": "string",
            "description": "Message type: 'comment' (visible to followers) or 'note' (internal note).",
            "enum": ["comment", "note"],
            "default": "comment"
        },
        "context": {
            "type": "object",
            "description": "Optional Odoo context overrides."
        }
    },
    "required": ["model", "id", "body"]
}
